def init_database():
    conn = sqlite3.connect(DATABASE_FILE)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS records (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            route TEXT,
            nationality TEXT,
            cargo_type TEXT,
            chinese_name TEXT NOT NULL,
            english_name TEXT NOT NULL,
            arrival_time TEXT NOT NULL,
            discharge_amount REAL NOT NULL,
            total_cargo REAL NOT NULL,
            ship_length REAL NOT NULL,
            ship_width REAL NOT NULL,
            dwt REAL NOT NULL,
            gt REAL NOT NULL,
            nt REAL NOT NULL,
            berth_type TEXT NOT NULL,
            agent TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            application_file TEXT,
            plan_file TEXT,
            channel_depth REAL,
            berth_time_a TEXT,
            tide_before_b REAL,
            tide_berth_c REAL,
            draft_berth_d REAL,
            departure_time_e TEXT,
            tide_departure_f REAL,
            tide_after_g REAL,
            draft_departure_h REAL,
            keel_height_i REAL
        )
    ''')
    conn.commit()
    conn.close()

# 潮水表读取函数
def load_tide_tables():
    """加载潮水表数据"""
    global _tide_cache
    
    try:
        # 读取湛江港潮水表
        if ZHANJIANG_TIDE_FILE.exists():
            df_zhanjiang = pd.read_excel(ZHANJIANG_TIDE_FILE)
            _tide_cache["zhanjiang"] = df_zhanjiang
            print(f"湛江港潮水表加载成功，共{len(df_zhanjiang)}天数据")
        else:
            print(f"警告: 湛江港潮水表文件不存在: {ZHANJIANG_TIDE_FILE}")
        
        # 读取硇洲岛潮水表
        if NIAOZHOU_TIDE_FILE.exists():
            df_niaozhou = pd.read_excel(NIAOZHOU_TIDE_FILE)
            _tide_cache["niaozhou"] = df_niaozhou
            print(f"硇洲岛潮水表加载成功，共{len(df_niaozhou)}天数据")
        else:
            print(f"警告: 硇洲岛潮水表文件不存在: {NIAOZHOU_TIDE_FILE}")
            
    except Exception as e:
        print(f"加载潮水表失败: {e}")

def parse_simple_time(time_str):
    """解析简化的时间格式，如 '7-1 1000' -> 2026-07-01 10:00"""
    try:
        # 当前年份
        current_year = datetime.now().year

        # 解析格式 "7-1 1000" 或 "07-01 1000"
        parts = time_str.strip().split()
        if len(parts) != 2:
            return None

        date_part, time_part = parts

        # 解析日期 "7-1" 或 "07-01"
        month_day = date_part.split('-')
        if len(month_day) != 2:
            return None

        month = int(month_day[0])
        day = int(month_day[1])

        # 解析时间 "1000" -> 10:00 或 "0930" -> 09:30
        if len(time_part) != 4:
            return None

        hour = int(time_part[:2])
        minute = int(time_part[2:])

        # 构建完整的datetime对象
        dt = datetime(current_year, month, day, hour, minute)
        print(f"解析时间: {time_str} -> {dt.strftime('%Y-%m-%d %H:%M:%S')} (小时: {hour}, 分钟: {minute})")
        return dt

    except Exception as e:
        print(f"时间解析失败: {time_str}, 错误: {e}")
        return None

def get_tide_height(location, date_time):
    """从潮水表中获取指定时间的潮高
    
    Args:
        location: "zhanjiang" 或 "niaozhou"
        date_time: datetime对象
    
    Returns:
        潮高（米），如果查询失败返回None
    """
    try:
        # 获取对应的潮水表
        df = _tide_cache.get(location)
        if df is None:
            print(f"潮水表未加载: {location}")
            return None
        
        # 获取日期的月-日格式
        month = date_time.month
        day = date_time.day
        hour = date_time.hour
        minute = date_time.minute
        year = date_time.year

        print(f"查询潮高: location={location}, 时间={date_time.strftime('%Y-%m-%d %H:%M:%S')}, 小时={hour}, 分钟={minute}")
        
        # 查找对应的行（A列是日期）
        # 潮水表中日期格式为 "2026-01-01"，需要精确匹配
        date_str = f"{year}-{month:02d}-{day:02d}"
        
        # 在A列中查找匹配的日期
        matching_row = None
        for idx, row in df.iterrows():
            # 检查第一列（A列）是否完全匹配日期
            first_col_value = str(df.iloc[idx, 0]).strip()
            if first_col_value == date_str:
                matching_row = idx
                break
        
        if matching_row is None:
            print(f"未找到日期 {date_str} 的潮水数据")
            return None
        
        # 判断是否是整点时间
        if minute == 0:
            # 如果是整点时间，直接获取对应整点的潮高
            hour_col_idx = None
            hour_str = f"{hour:02d}00"  # 将小时转换为 "1000" 格式
            
            for col_idx in range(1, len(df.columns)):
                col_header = str(df.columns[col_idx]).strip()
                # 检查列标题是否匹配小时格式
                if col_header == hour_str:
                    hour_col_idx = col_idx
                    break
            
            if hour_col_idx is None:
                print(f"未找到小时 {hour} 的潮水数据列")
                return None
            
            # 获取潮高值（厘米）
            tide_cm = df.iloc[matching_row, hour_col_idx]
            
            # 处理可能的NaN值
            if pd.isna(tide_cm):
                print(f"日期 {date_str} 小时 {hour} 的潮高数据为空")
                return None
            
            # 转换为米，保留两位小数
            tide_m = round(float(tide_cm) / 100.0, 2)
            print(f"整点时间潮高: {hour:02d}:00 = {tide_m:.2f}米")

            return tide_m
        else:
            # 如果不是整点时间，需要计算前后两个整点的潮高平均值
            print(f"非整点时间，需要进行插值计算")
            current_hour_tide = get_hour_tide(df, matching_row, hour)
            
            # 计算下一个小时的潮高
            next_hour = hour + 1
            if next_hour >= 24:
                # 如果是23点之后，需要查找下一天的数据
                next_date_str = f"{year}-{month:02d}-{day + 1:02d}" if day + 1 <= 31 else f"{year}-{month + 1:02d}-01"
                next_matching_row = None
                for idx, row in df.iterrows():
                    first_col_value = str(df.iloc[idx, 0]).strip()
                    if first_col_value == next_date_str:
                        next_matching_row = idx
                        break
                
                if next_matching_row is None:
                    print(f"未找到日期 {next_date_str} 的潮水数据")
                    return None
                
                next_hour_tide = get_hour_tide(df, next_matching_row, 0)  # 0点
            else:
                next_hour_tide = get_hour_tide(df, matching_row, next_hour)
            
            if current_hour_tide is None or next_hour_tide is None:
                return None

            # 计算权重比例
            weight = minute / 60.0

            # 线性插值计算潮高，保留两位小数
            tide_m = round(current_hour_tide * (1 - weight) + next_hour_tide * weight, 2)
            print(f"非整点时间插值: {hour:02d}:{minute:02d} = {current_hour_tide:.2f} × {(1-weight):.2f} + {next_hour_tide:.2f} × {weight:.2f} = {tide_m:.2f}米")

            return tide_m
        
    except Exception as e:
        print(f"获取潮高失败: {e}")
        return None

def get_hour_tide(df, row_idx, hour):
    """获取指定行和小时的潮高
    
    Args:
        df: 潮水表DataFrame
        row_idx: 行索引
        hour: 小时（0-23）
    
    Returns:
        潮高（米），如果查询失败返回None
    """
    try:
        # 获取对应小时的潮高数据
        hour_col_idx = None
        hour_str = f"{hour:02d}00"  # 将小时转换为 "0000", "0100", ... 格式
        
        for col_idx in range(1, len(df.columns)):
            col_header = str(df.columns[col_idx]).strip()
            # 检查列标题是否匹配小时格式
            if col_header == hour_str:
                hour_col_idx = col_idx
                break
        
        if hour_col_idx is None:
            print(f"未找到小时 {hour} 的潮水数据列")
            return None
        
        # 获取潮高值（厘米）
        tide_cm = df.iloc[row_idx, hour_col_idx]

        # 处理可能的NaN值
        if pd.isna(tide_cm):
            return None

        # 转换为米，保留两位小数
        tide_m = round(float(tide_cm) / 100.0, 2)
        print(f"整点时间潮高: {hour:02d}:00 = {tide_m:.2f}米")

        return tide_m
        
    except Exception as e:
        print(f"获取小时潮高失败: {e}")
        return None

def auto_calculate_tides(berth_time_str, departure_time_str, berth_type):
    """自动计算潮高数据
    
    Args:
        berth_time_str: 靠泊时间字符串（简化格式）
        departure_time_str: 离泊时间字符串（简化格式）
        berth_type: 泊位类型
    
    Returns:
        包含所有潮高数据的字典
    """
    # 解析时间
    berth_time = parse_simple_time(berth_time_str)
    departure_time = parse_simple_time(departure_time_str)
    
    if berth_time is None or departure_time is None:
        return None
    
    # 计算关键时间点
    berth_before_1h = berth_time - timedelta(hours=1)
    departure_after_1h = departure_time + timedelta(hours=1)
    
    # 获取潮高数据
    tide_data = {
        "berth_time": berth_time,
        "departure_time": departure_time,
        "berth_before_1h": berth_before_1h,
        "departure_after_1h": departure_after_1h,
        
        # 湛江港潮高
        "tide_berth_c": get_tide_height("zhanjiang", berth_time),
        "tide_departure_f": get_tide_height("zhanjiang", departure_time),
        
        # 硇洲岛潮高
        "tide_before_b": get_tide_height("niaozhou", berth_before_1h),
        "tide_after_g": get_tide_height("niaozhou", departure_after_1h),
    }
    
    return tide_data

