# 数据库操作
def get_db_connection():
    conn = sqlite3.connect(DATABASE_FILE)
    conn.row_factory = sqlite3.Row
    return conn

def save_record(ship_info: ShipInfo, application_file: str, plan_file: str):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('''
        INSERT INTO records (
            route, nationality, cargo_type, chinese_name, english_name, arrival_time, discharge_amount,
            total_cargo, ship_length, ship_width, dwt, gt, nt,
            berth_type, agent, application_file, plan_file,
            channel_depth, berth_time_a, tide_before_b, tide_berth_c,
            draft_berth_d, departure_time_e, tide_departure_f,
            tide_after_g, draft_departure_h, keel_height_i
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ''', (
        ship_info.route, ship_info.nationality, ship_info.cargo_type, ship_info.chinese_name, ship_info.english_name, ship_info.arrival_time,
        ship_info.discharge_amount, ship_info.total_cargo, ship_info.ship_length,
        ship_info.ship_width, ship_info.dwt, ship_info.gt, ship_info.nt,
        ship_info.berth_type, ship_info.agent,
        application_file, plan_file,
        ship_info.channel_depth, ship_info.berth_time_a, ship_info.tide_before_b,
        ship_info.tide_berth_c, ship_info.draft_berth_d, ship_info.departure_time_e,
        ship_info.tide_departure_f, ship_info.tide_after_g, ship_info.draft_departure_h,
        ship_info.keel_height_i
    ))
    conn.commit()
    conn.close()
    return cursor.lastrowid

# 文档生成功能
def replace_text_in_docx(doc, replacements):
    """在docx文档中替换文本"""
    # 替换段落中的文本
    for paragraph in doc.paragraphs:
        for old_text, new_text in replacements.items():
            if old_text in paragraph.text:
                paragraph.text = paragraph.text.replace(old_text, new_text)
    
    # 替换表格中的文本
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for paragraph in cell.paragraphs:
                    for old_text, new_text in replacements.items():
                        if old_text in paragraph.text:
                            paragraph.text = paragraph.text.replace(old_text, new_text)
    
    return doc

def generate_documents(ship_info: ShipInfo):
    """生成海事申请和进出港方案文档"""
    # 确定泊位类型目录
    berth_type_dir = None
    for berth in BERTH_TYPES:
        if berth["code"] == ship_info.berth_type:
            berth_type_dir = berth["name"]
            break
    
    if not berth_type_dir:
        raise HTTPException(status_code=400, detail="无效的泊位类型")
    
    template_path = TEMPLATE_DIR / berth_type_dir
    if not template_path.exists():
        raise HTTPException(status_code=404, detail="模板目录不存在")
    
    # 查找模板文件
    application_template = None
    plan_template = None
    
    for file in template_path.glob("*.docx"):
        if "申请" in file.name and "海事局" in file.name:
            application_template = file
        elif "方案" in file.name and "保障" in file.name:
            plan_template = file
    
    if not application_template or not plan_template:
        raise HTTPException(status_code=404, detail=f"模板文件不完整 - 申请模板: {application_template}, 方案模板: {plan_template}")
    
    # 生成文件名
    timestamp = datetime.now().strftime("%Y%m%d%H%M%S")
    application_filename = f"{timestamp}_{ship_info.chinese_name}_海事局申请.docx"
    plan_filename = f"{timestamp}_{ship_info.chinese_name}_保障方案.docx"
    
    application_output = OUTPUT_DIR / application_filename
    plan_output = OUTPUT_DIR / plan_filename
    
    # 生成申请文档
    generate_application_document(application_template, application_output, ship_info)
    
    # 生成保障方案文档
    generate_plan_document(plan_template, plan_output, ship_info)
    
    return str(application_output), str(plan_output)

def generate_application_document(template_path, output_path, ship_info):
    """生成海事局申请文档"""
    doc = Document(template_path)
    
    # 构建替换字典（基于模板中的示例数据）
    replacements = build_replacement_dict(doc, ship_info)
    
    # 执行替换
    doc = replace_text_in_docx(doc, replacements)
    
    # 保存文档
    doc.save(output_path)

def generate_plan_document(template_path, output_path, ship_info):
    """生成进出港安全保障方案文档"""
    doc = Document(template_path)
    
    # 构建替换字典
    replacements = build_replacement_dict(doc, ship_info)
    
    # 执行替换
    doc = replace_text_in_docx(doc, replacements)
    
    # 保存文档
    doc.save(output_path)

def build_replacement_dict(doc, ship_info):
    """构建替换字典，基于模板中的具体内容"""
    replacements = {}
    
    # 读取模板内容，识别需要替换的数据
    full_text = ""
    for para in doc.paragraphs:
        full_text += para.text + "\n"
    
    # 提取模板中的示例数据（注意中文引号）
    sample_chinese_name = extract_sample_data(full_text, r'[""\u201c\u201d](.+?)[""\u201c\u201d]\s*轮')
    sample_english_name = extract_sample_data(full_text, r'\(([A-Za-z\s]+)\)')
    sample_agent = extract_sample_data(full_text, r'(.+?代理有限公司).+?代理')
    
    # 构建替换映射
    if sample_chinese_name:
        # 支持中文和英文引号
        for quote in ['"', '"', '"', '"']:
            old_chinese_name = f'{quote}{sample_chinese_name}{quote}轮'
            new_chinese_name = f'{quote}{ship_info.chinese_name}{quote}轮'
            replacements[old_chinese_name] = new_chinese_name
        replacements[sample_chinese_name] = ship_info.chinese_name
    
    if sample_english_name:
        old_english_name = f'({sample_english_name})'
        new_english_name = f'({ship_info.english_name})'
        replacements[old_english_name] = new_english_name
    
    if sample_agent:
        # 移除代理后的内容，只保留公司名
        agent_match = re.search(r'(.+?代理有限公司)', sample_agent)
        if agent_match:
            old_agent = agent_match.group(1)
            replacements[old_agent] = ship_info.agent
    
    # 替换数字数据（吨位、尺寸等）
    replacements = update_numeric_replacements(replacements, full_text, ship_info)
    
    # 添加潮水计算相关的替换
    replacements.update(generate_tide_replacements(ship_info))
    
    # 添加安全保障小组相关的替换
    replacements.update(generate_safety_team_replacements(ship_info))
    
    return replacements

def extract_sample_data(text, pattern):
    """从文本中提取示例数据"""
    match = re.search(pattern, text)
    return match.group(1).strip() if match else None

def update_numeric_replacements(replacements, text, ship_info):
    """更新数字数据的替换，所有数字保留两位小数"""
    # 提取并替换吨位
    tonnage_patterns = {
        '总吨': round(ship_info.gt, 2),
        '净吨': round(ship_info.nt, 2),
        '载重吨': round(ship_info.dwt, 2),
        '卸.*?吨': round(ship_info.discharge_amount, 2),
        '总载货.*?吨': round(ship_info.total_cargo, 2),
    }

    for key, value in tonnage_patterns.items():
        pattern = rf'(\d+(?:,\d+)*)\s*{key}'
        matches = re.findall(pattern, text)
        for match in matches:
            old_value = match.replace(',', '')
            replacements[f"{old_value}{key}"] = f"{value}{key}"
            replacements[f"{old_value} {key}"] = f"{value} {key}"

    # 提取并替换尺寸
    dimension_patterns = {
        '长度': round(ship_info.ship_length, 2),
        '宽度': round(ship_info.ship_width, 2),
    }

    for key, value in dimension_patterns.items():
        pattern = rf'{key}.*?(\d+(?:\.\d+)?)\s*米'
        matches = re.findall(pattern, text)
        for match in matches:
            old_pattern = rf'{key}.*?{match}\s*米'
            replacements[old_pattern] = f'{key}为{value}米'

    return replacements

def parse_time_to_datetime(time_str):
    """解析时间字符串为datetime对象，支持简化格式"""
    try:
        # 先尝试简化格式 "7-1 1000"
        simple_parsed = parse_simple_time(time_str)
        if simple_parsed:
            return simple_parsed
            
        # 尝试标准格式
        for fmt in ['%Y-%m-%d %H:%M', '%Y-%m-%dT%H:%M', '%Y-%m-%d %H:%M:%S']:
            try:
                return datetime.strptime(time_str, fmt)
            except ValueError:
                continue
        return None
    except Exception:
        return None

def format_time_display(dt):
    """格式化时间显示"""
    if dt is None:
        return ""
    return dt.strftime("%m月%d日%H:%M时")

def calculate_time_offset(time_str, offset_hours):
    """计算时间偏移"""
    dt = parse_time_to_datetime(time_str)
    if dt is None:
        return ""
    offset_time = dt + timedelta(hours=offset_hours)
    return format_time_display(offset_time)

def generate_tide_replacements(ship_info):
    """生成潮水计算相关的替换"""
    replacements = {}
    
    # 基础参数，确保所有数值保留两位小数
    X = ship_info.berth_type  # 泊位类型
    Y = round(ship_info.channel_depth, 2)  # 航道水深
    A = ship_info.berth_time_a  # 靠泊时间
    B = round(ship_info.tide_before_b, 2) if ship_info.tide_before_b is not None else None  # 靠泊前1小时硇洲潮高
    C = round(ship_info.tide_berth_c, 2) if ship_info.tide_berth_c is not None else None  # 靠泊时湛江港潮高
    D = round(ship_info.draft_berth_d, 2)  # 船舶靠泊吃水
    E = ship_info.departure_time_e  # 离泊时间
    F = round(ship_info.tide_departure_f, 2) if ship_info.tide_departure_f is not None else None  # 离泊时湛江潮高
    G = round(ship_info.tide_after_g, 2) if ship_info.tide_after_g is not None else None  # 离泊时已1小时后的硇洲潮高
    H = round(ship_info.draft_departure_h, 2)  # 船舶离泊吃水
    I = round(ship_info.keel_height_i, 2)  # 龙骨高度
    
    # 时间格式化
    A_time = parse_time_to_datetime(A)
    A_display = format_time_display(A_time)
    A_before_1h = calculate_time_offset(A, -1)
    E_time = parse_time_to_datetime(E)
    E_display = format_time_display(E_time)
    E_after_1h = calculate_time_offset(E, 1)
    
    # 根据泊位类型生成不同的内容
    if X == "601":
        replacements.update(generate_berth_601_content(
            Y, A_display, A_before_1h, B, C, D, E_display, F, G, H, I
        ))
    elif X == "400":
        replacements.update(generate_berth_400_content(
            Y, A_display, A_before_1h, B, C, D, E_display, F, G, H, I
        ))
    elif X == "300":
        replacements.update(generate_berth_300_content(
            Y, A_display, B, C, D, E_display, F, G, H, I
        ))
    elif X == "200":
        replacements.update(generate_berth_200_content(
            Y, A_display, A_before_1h, B, C, D, E_display, F, G, H, I
        ))
    elif X == "210":
        replacements.update(generate_berth_210_content(
            Y, A_display, A_before_1h, B, C, D, E_display, F, G, H, I
        ))
    
    return replacements

def generate_berth_601_content(Y, A, A_before, B, C, D, E, F, G, H, I):
    """生成601泊位的内容"""
    replacements = {}
    
    # 计算公式
    arrival_safety_depth = Y + B - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    departure_safety_depth = 24.0 + F - H
    
    # 一、海事申请
    replacements["海事申请内容"] = f"""一、海事申请
1、{A_before}时（硇洲潮高{B}米），龙腾航道浅点水深-{Y}米，富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米，比例为{arrival_safety_depth:.2f}÷{D}={arrival_ratio:.2f}%。符合安全要求。{A}时靠601泊位，601泊位码头前沿水深为24.0米，码头长度450米，满足靠泊要求。
2、{E}时（潮高{F}米）离601泊位，离泊吃水{H}米，601码头港池水深为24.0米，港池富余水深24.0+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。"""
    
    # 二、引航方案
    replacement_berth_safety_depth = 24.0 + C - D
    departure_channel_safety_depth = Y + G - H
    departure_channel_ratio = (departure_channel_safety_depth / H) * 100 if H != 0 else 0
    
    replacements["引航方案内容"] = f"""二、引航方案
（一）进港和靠泊
1．人员的指派及接送方式
根据该船情况指派一名一级或以上级别的责任引航员负责引航工作，引航员乘直升机（引航船或引航艇）登轮。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{A_before}潮高{B}米，龙腾航道水深为-{Y}米，富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米，富余水深与吃水比为{arrival_safety_depth:.2f}/{D}={arrival_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求。
考虑到在龙腾航道35#灯标—37#灯标之间和43#灯浮—47#灯浮航段中心线右侧水域有浅点，船舶进港时应靠近航道中心线航道水域航行，避开航道中浅点水域，确保富余水深满足要求，保障航行安全。
3．船舶靠泊码头的富余水深必须符合有关规定要求
湛江港{A}时潮高{C}米，601码头回旋水域底标高为-24.0米，港池富余水深24.0+{C}-{D}={replacement_berth_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
（二）离泊和出港
1．人员的指派及接送方式
根据该船情况指派一名一级或以上级别的责任引航员负责引航工作，引航员乘直升机（引航船或引航艇）离船。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{E}时潮高{F}米，龙腾航道水深为-{Y}米，富余水深为{Y}+{G}-{H}={departure_channel_safety_depth:.2f}米，富余水深与吃水比为{departure_channel_safety_depth:.2f}/{H}={departure_channel_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求.
3．船舶离泊码头的富余水深必须符合有关规定要求
湛江港{E}时潮高{F}米，601码头回旋水域底标高为-24.0米，港池富余水深24.0+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。"""
    
    return replacements

