def generate_berth_300_content(Y, A, B, C, D, E, F, G, H, I):
    """生成300泊位的内容"""
    replacements = {}
    
    # 计算公式
    arrival_safety_depth = Y + C - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    berth_safety_depth = 15.1 + C - D
    arrival_clearance_height = 48 + 4.54 - C + D - I
    departure_clearance_height = 48 + 4.54 - F + H - I
    departure_safety_depth = 13.6 + F - H
    departure_ratio = ((Y + F - H) / H) * 100 if H != 0 else 0
    bridge_height_arrival = (48 + 4.54) - C
    ship_height_arrival = I - D
    bridge_clearance_arrival = bridge_height_arrival - ship_height_arrival
    bridge_height_departure = (48 + 4.54) - F
    ship_height_departure = I - H
    bridge_clearance_departure = bridge_height_departure - ship_height_departure
    
    replacements["海事申请内容"] = f"""一、海事申请
1、{A}时（湛江潮高{C}米）靠三分公司300泊，进港航道浅点水深{Y}，富余水深为{Y}+{C}-{D}={arrival_safety_depth:.2f}米，比例：{arrival_safety_depth:.2f}÷{D}={arrival_ratio:.2f}%，满足通航要求；300泊水深15.1米，富余水深：15.1+{C}-{D}={berth_safety_depth:.2f}，满足靠泊要求。
2、本次通航富余高度：48+4.54-{C}+{D}-{I}={arrival_clearance_height:.2f}米。
3、出来通航富余高度：48+4.54-{F}+{H}-{I}={departure_clearance_height:.2f}米（{E}时出来，潮高{F}米，船舶吃水约{H}米）。"""
    
    replacements["引航方案内容"] = f"""二、引航方案
（一）进港和靠泊
1．人员的指派及接送方式
根据该船情况指派一名二级或以上级别的责任引航员负责引航工作，引航员乘直升机（引航船或引航艇）登轮。
2．船舶过海湾大桥富余高度及航道富余水深比必须符合有关规定要求
湛江港{A}时潮高{C}米，当时海湾大桥水上高度为（48+4.54）-{C}={bridge_height_arrival:.2f}米，大船水上高度{I}-{D}={ship_height_arrival:.2f}米，海湾大桥净空富余高度为{bridge_height_arrival:.2f}-{ship_height_arrival:.2f}={bridge_clearance_arrival:.2f}米；航道富余水深与吃水比为（{Y}+{C}-{D})/{D}={arrival_safety_depth:.2f}/{D}={arrival_ratio:.2f}%，符合有关船舶通过海湾大桥及航道富余水深规定要求。
3．船舶靠泊码头的富余水深必须符合有关规定要求
湛江港{A}时潮高{C}米，码头富余水深15.1+{C}-{D}={berth_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
（二）离泊和出港
1．人员的指派及接送方式
根据该船情况指派一名二级或以上级别的责任引航员负责引航工作，引航员乘直升机（引航船或引航艇）离船。
2．船舶离泊码头的富余水深必须符合有关规定要求
湛江港{E}时潮高{F}米，300港池水深为13.6米，港池富余水深13.6+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
3.船舶过海湾大桥富余高度及航道富余水深比必须符合有关规定要求
湛江港{E}时潮高{F}，当时海湾大桥水上高度为（48+4.54）-{F}={bridge_height_departure:.2f}米，大船水上高度{I}-{H}={ship_height_departure:.2f}米，海湾大桥净空富余高度为{bridge_height_departure:.2f}-{ship_height_departure:.2f}={bridge_clearance_departure:.2f}米；航道富余水深与吃水比为（{Y}+{F}-{H})/{H}={departure_ratio:.2f}%，符合有关船舶通过海湾大桥及航道富余水深规定要求。"""
    
    return replacements

def generate_berth_200_content(Y, A, A_before, B, C, D, E, F, G, H, I):
    """生成200泊位的内容"""
    replacements = {}
    
    # 计算公式
    arrival_safety_depth = Y + B - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    departure_safety_depth = 22.3 + F - H
    berth_safety_depth = 22.3 + C - D
    departure_channel_safety_depth = Y + G - H
    departure_channel_ratio = (departure_channel_safety_depth / H) * 100 if H != 0 else 0
    
    replacements["海事申请内容"] = f"""一、海事申请
1、龙腾航道浅点水深{Y}米，{A_before}时（硇洲潮高{B}米），进港富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米。富裕水深比例：{arrival_safety_depth:.2f}÷{D}={arrival_ratio:.2f}%，符合安全要求。{A}时靠200#泊，200＃泊位水深23.4米，满足船舶靠泊要求。我港对此类船舶靠泊作业积累了丰富的经验，在作业过程中我们将加强安全值班，做好防火、防漏、防污等工作。为确保船舶安全靠离码头，届时特请贵局进行清道护航工作。
2、{E}时（潮高{F}米）离200泊，离泊吃水{H}米，200泊位港池水深为-22.3米，港池富余水深22.3+{F}-{H}={departure_safety_depth:.2f}米，满足安全要求。"""
    
    replacements["引航方案内容"] = f"""二、引航方案
（一）进港和靠泊
1．人员的指派及接送方式
根据该船情况应指派一名一级或以上级别的引航员主引，另加一名全能二级或以上级别引航员作为副班引航员。引航员乘直升机（如果飞机受影响将改用引航船或引航艇）登轮。引航员登轮位置在20°59.5′00″N，110°55″E附近水域。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{A_before}时潮高{B}米，龙腾航道水深为-{Y}米，富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米，富余水深与吃水比为{arrival_safety_depth:.2f}/{D}={arrival_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求。
考虑到在龙腾航道35#灯标—37#灯标之间和43#灯浮—47#灯浮航段中心线右侧水域有浅点，船舶进港时应靠近航道中心线航道水域航行，避开航道中浅点水域，确保富余水深满足要求，保障航行安全。
3．船舶靠泊码头的富余水深必须符合有关规定要求
湛江港{A}时潮高{C}米，200码头港池水深为22.3米，港池富余水深22.3+{C}-{D}={berth_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
（二）离泊和出港
1．人员的指派及接送方式
根据该船情况指派一名一级的责任引航员负责引航工作。引航员乘直升机（引航船或引航艇）离船。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{E}时潮高{G}米，龙腾航道水深为-{Y}米，富余水深为{Y}+{G}-{H}={departure_channel_safety_depth:.2f}米，富余水深与吃水比为{departure_channel_safety_depth:.2f}/{H}={departure_channel_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求.
3．船舶离泊码头的富余水深必须符合有关规定要求
要求平潮缓流时离泊，湛江港{E}时潮高{F}米，200码头港池水深为22.3米，港池富余水深22.3+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。"""
    
    return replacements

