def generate_safety_team_replacements(ship_info):
    """生成安全保障小组相关的替换"""
    replacements = {}
    
    # 根据代理公司获取对应的安全保障小组
    safety_team = SAFETY_TEAMS.get(ship_info.agent)
    
    if safety_team:
        # 生成完整的保障小组文本
        team_leader = safety_team.get("组长", "")
        vice_leader = safety_team.get("副组长", "")
        members = safety_team.get("成员", "")
        
        safety_team_text = f"""组长：{team_leader}
副组长：{vice_leader}
成员：{members}"""
        
        # 替换变量
        replacements["{安全保障小组}"] = safety_team_text
        replacements["安全保障小组"] = safety_team_text
    else:
        # 如果没有找到对应的代理公司，使用默认值
        replacements["{安全保障小组}"] = "组长：待定\n副组长：待定\n成员：待定"
        replacements["安全保障小组"] = "组长：待定\n副组长：待定\n成员：待定"
    
    return replacements

