@app.post("/api/parse-and-calculate")
async def parse_and_calculate_endpoint(request: TideCalculationRequest):
    """解析时间并计算潮高（一步完成）"""
    # 解析时间
    tide_data = auto_calculate_tides(request.berth_time, request.departure_time, request.berth_type)
    
    if tide_data is None:
        raise HTTPException(status_code=400, detail="时间解析或潮高计算失败")
    
    # 获取航道水深
    channel_depth = CHANNEL_DEPTHS.get(request.berth_type, 18.0)
    
    result = {
        "times": {
            "berth_time": format_time_display(tide_data["berth_time"]),
            "departure_time": format_time_display(tide_data["departure_time"]),
            "berth_before_1h": format_time_display(tide_data["berth_before_1h"]),
            "departure_after_1h": format_time_display(tide_data["departure_after_1h"]),
        },
        "tides": {
            "tide_before_b": round(tide_data["tide_before_b"], 2) if tide_data["tide_before_b"] is not None else None,
            "tide_berth_c": round(tide_data["tide_berth_c"], 2) if tide_data["tide_berth_c"] is not None else None,
            "tide_departure_f": round(tide_data["tide_departure_f"], 2) if tide_data["tide_departure_f"] is not None else None,
            "tide_after_g": round(tide_data["tide_after_g"], 2) if tide_data["tide_after_g"] is not None else None,
        },
        "channel_depth": round(channel_depth, 2)
    }
    
    return result

@app.post("/api/generate-documents")
async def generate_documents_endpoint(ship_info: ShipInfo):
    """生成文档内容"""
    try:
        # 生成文本内容
        application_text, plan_text = generate_text_content(ship_info)
        return {
            "success": True,
            "application_text": application_text,
            "plan_text": plan_text,
            "message": "文档生成成功"
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

def generate_text_content(ship_info: ShipInfo):
    """生成海事申请和保障方案的纯文本内容"""

    # 格式化时间显示
    def format_time_display(time_str):
        dt = parse_simple_time(time_str)
        if dt:
            return f"{dt.month}月{dt.day}日{dt.hour:02d}:{dt.minute:02d}时"
        return time_str

    # 计算关键时间点
    berth_time = parse_simple_time(ship_info.berth_time_a)
    departure_time = parse_simple_time(ship_info.departure_time_e)
    berth_before_1h = berth_time - timedelta(hours=1) if berth_time else None
    departure_after_1h = departure_time + timedelta(hours=1) if departure_time else None

    # 获取显示格式的时间
    A_display = format_time_display(ship_info.berth_time_a)
    E_display = format_time_display(ship_info.departure_time_e)
    A_before_display = format_time_display(f"{berth_before_1h.month}-{berth_before_1h.day} {berth_before_1h.hour:02d}{berth_before_1h.minute:02d}") if berth_before_1h else "-"
    E_after_display = format_time_display(f"{departure_after_1h.month}-{departure_after_1h.day} {departure_after_1h.hour:02d}{departure_after_1h.minute:02d}") if departure_after_1h else "-"

    # 潮高数据
    B = ship_info.tide_before_b  # 靠泊前1小时硇洲潮高
    C = ship_info.tide_berth_c  # 靠泊时湛江潮高
    D = ship_info.draft_berth_d  # 靠泊吃水
    F = ship_info.tide_departure_f  # 离泊时湛江潮高
    G = ship_info.tide_after_g  # 离泊后1小时硇洲潮高
    H = ship_info.draft_departure_h  # 离泊吃水
    I = ship_info.keel_height_i  # 龙骨高度
    Y = ship_info.channel_depth  # 航道水深

    # 当前日期
    current_date = datetime.now().strftime("%Y年%m月%d日")

    # 获取安全保障小组信息
    safety_team_replacements = generate_safety_team_replacements(ship_info)
    safety_team_text = safety_team_replacements.get("{安全保障小组}", "组长：待定\n副组长：待定\n成员：待定")

    # 根据泊位类型生成不同的内容
    if ship_info.berth_type == "300":
        return generate_berth_300_text_content(ship_info, Y, A_display, A_before_display, E_display, E_after_display, B, C, D, F, G, H, I, safety_team_text, current_date)
    elif ship_info.berth_type == "210":
        return generate_berth_210_text_content(ship_info, Y, A_display, A_before_display, E_display, E_after_display, B, C, D, F, G, H, I, safety_team_text, current_date)
    elif ship_info.berth_type == "400":
        return generate_berth_400_text_content(ship_info, Y, A_display, A_before_display, E_display, E_after_display, B, C, D, F, G, H, I, safety_team_text, current_date)
    elif ship_info.berth_type == "601":
        return generate_berth_601_text_content(ship_info, Y, A_display, A_before_display, E_display, E_after_display, B, C, D, F, G, H, I, safety_team_text, current_date)
    else:
        return generate_berth_200_text_content(ship_info, Y, A_display, A_before_display, E_display, E_after_display, B, C, D, F, G, H, I, safety_team_text, current_date)

def generate_berth_200_text_content(ship_info, Y, A, A_before, E, E_after, B, C, D, F, G, H, I, safety_team_text, current_date):
    """生成200泊位的文本内容 - 完整模板格式"""
    # 基础变量
    chinese_name = ship_info.chinese_name
    english_name = ship_info.english_name
    agent = ship_info.agent
    nationality = ship_info.nationality
    route = ship_info.route
    arrival_time = ship_info.arrival_time
    cargo_type = ship_info.cargo_type
    discharge_amount = ship_info.discharge_amount
    total_cargo = ship_info.total_cargo
    ship_length = ship_info.ship_length
    ship_width = ship_info.ship_width
    gt = ship_info.gt
    nt = ship_info.nt
    dwt = ship_info.dwt
    
    # 时间变量
    berth_time_a = ship_info.berth_time_a
    departure_time_e = ship_info.departure_time_e
    
    # 潮水和吃水变量
    channel_depth = ship_info.channel_depth
    tide_before_b = ship_info.tide_before_b
    tide_berth_c = ship_info.tide_berth_c
    draft_berth_d = ship_info.draft_berth_d
    tide_departure_f = ship_info.tide_departure_f
    tide_after_g = ship_info.tide_after_g
    draft_departure_h = ship_info.draft_departure_h
    keel_height_i = ship_info.keel_height_i
    
    # 计算各种时间偏移
    berth_time = parse_simple_time(berth_time_a)
    departure_time = parse_simple_time(departure_time_e)
    
    berth_before_5h = berth_time - timedelta(hours=5) if berth_time else None
    berth_before_2h = berth_time - timedelta(hours=2) if berth_time else None
    berth_before_1_5h = berth_time - timedelta(hours=1.5) if berth_time else None
    berth_before_1h = berth_time - timedelta(hours=1) if berth_time else None
    berth_before_50min = berth_time - timedelta(minutes=50) if berth_time else None
    berth_before_0_5h = berth_time - timedelta(minutes=30) if berth_time else None
    
    departure_after_2h = departure_time + timedelta(hours=2) if departure_time else None
    departure_after_3h = departure_time + timedelta(hours=3) if departure_time else None
    departure_after_3h20min = departure_time + timedelta(hours=3, minutes=20) if departure_time else None
    
    # 计算结果
    arrival_safety_depth = Y + B - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    departure_safety_depth = 22.3 + F - H
    berth_safety_depth = 22.3 + C - D
    departure_channel_safety_depth = Y + G - H
    departure_channel_ratio = (departure_channel_safety_depth / H) * 100 if H != 0 else 0
    
    # 海事申请
    application_text = f"""关于接靠"{chinese_name}"轮的申请
湛江海事局：
现有{agent}代理{nationality}籍(航线：{route})"{chinese_name}"轮({english_name}) 预{arrival_time}抵湛江卸{cargo_type}约{discharge_amount}吨（载货{total_cargo}吨）。该轮总吨{gt},净吨{nt},载重吨{dwt}吨,长度{ship_length}米,宽度{ship_width}米,抵港吃水{D}米。我港可接受该轮抵港卸货，计划安排该轮{A}靠200#泊位，于{E}离200泊，离泊吃水{H}米。
1、龙腾航道浅点水深{Y}米，{A_before}（硇洲潮高{B}米），进港富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米。富裕水深比例：（{Y}+{B}-{D}）÷{D}={arrival_ratio:.2f}%，符合安全要求。{A}靠200#泊，200＃泊位水深为22.30米，满足船舶靠泊要求。我港对此类船舶靠泊作业积累了丰富的经验，在作业过程中我们将加强安全值班，做好防火、防漏、防污等工作。为确保船舶安全靠离码头，届时特请贵局进行清道护航工作。
2、{E}时（潮高{F}米）离200泊，离泊吃水{H}米，200泊位港池水深为22.30米，港池富余水深22.30+{F}-{H}={departure_safety_depth:.2f}米，满足安全要求。
3、为确保船舶安全靠离码头，届时由船方委托代理向清道单位申请安全保障船执行安全保障任务。
    此申请妥否？请批示。
 
湛江港（集团）股份有限公司
 {current_date}"""

    # 保障方案
    plan_text = f"""\"{chinese_name}\"轮进出港安全保障方案

为确保"{chinese_name}"轮进出湛江港的安全，现由{agent}代理船方委托湛江港引航站制定"{chinese_name}"轮安全保障方案。在"{chinese_name}"轮进出港期间，{agent}将履行该方案的措施和要求，确保安全。
一、代理和船舶资料及计划
{agent}代理的{nationality}籍(航线：{route})"{chinese_name}"轮({english_name}) 预{arrival_time}抵湛江。该轮总吨{gt},净吨{nt},载重吨{dwt}吨,长度{ship_length}米,宽度{ship_width}米,抵港吃水{D}米。计划安排该轮{A}靠200#泊位，于{E}离200泊，离泊吃水{H}米。
二、根据船舶的靠离泊计划，成立安全保障工作小组
{safety_team_text}
   工作小组根据该轮进出港和靠离泊情况以及航道、码头、水文、气象等各种通航条件，认为其符合靠离泊安全规定，为确保安全特制定以下安全保障方案。
三、船舶进出港和靠离泊安全保障方案
（一）进港和靠泊
1．人员的指派及接送方式
根据该船情况指派一名一级或以上级别的责任引航员负责引航工作，另加一名全能二级或以上级别引航员作为副班引航员；引航员乘直升机（引航船或引航艇）登轮。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{A_before}潮高{B}米，龙腾航道水深为-{Y}米，富余水深为{Y}+{B}-{D}={arrival_safety_depth:.2f}米，富余水深与吃水比为（{Y}+{B}-{D}）/{D}={arrival_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求。
考虑到在龙腾航道35#灯标—37#灯标之间和43#灯浮—47#灯浮航段中心线右侧水域有浅点，船舶进港时应靠近航道中心线航道水域航行，避开航道中浅点水域，确保富余水深满足要求，保障航行安全。
3．船舶靠泊码头的富余水深必须符合有关规定要求
湛江港{A}潮高{C}米，200码头港池水深为22.30米，港池富余水深22.30+{C}-{D}={berth_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
4．气象条件要求
风力7级以下，能见度1500米以上。
5．拖轮使用
  根据该船的吃水情况，港区的风、流条件，经测算需4-5艘港作拖轮协助靠泊，其中大拖轮：5000HP或以上、中拖轮：4000-5000HP。
（二）离泊和出港
1．人员的指派及接送方式
根据该船情况指派一名一级或以上级别的责任引航员负责引航工作，引航员乘直升机（引航船或引航艇）离船。
2．船舶通过龙腾航道的富余水深必须符合有关规定要求
湛江硇洲岛{E_after}潮高{G}，龙腾航道水深为-{Y}米，富余水深为{Y}+{G}-{H}={departure_channel_safety_depth:.2f}米，富余水深与吃水比为（{Y}+{G}-{H}）/{H}={departure_channel_ratio:.2f}%，以上符合有关船舶通过龙腾航道规定的富余水深要求。
3．船舶离泊码头的富余水深必须符合有关规定要求
要求平潮缓流时离泊，湛江港{E}潮高{F}米，200码头港池水深为22.30米，港池富余水深22.30+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
4．气象条件要求
风力7级以下，能见度1500米以上。
5．拖轮使用
根据该船的吃水情况，港区的风、流条件，经测算需4-5艘港作拖轮协助离泊，其中大拖轮：5000HP或以上、中拖轮：4000-5000HP.
（三）船舶、安全保障船、协助靠离泊拖轮的职责
1．船舶
（1）确保船舶处于良好状态，主机、辅机、舵机、锚机处于良好状态，各种航海仪器能正常使用；
（2）与安全保障船和湛江交管中心保持联系，获取安全相关通航信息；
（3）进出港时如发现有碍航行安全的障碍物（船舶）或气象、水文、条件发生不利变化，影响船舶安全进出港和靠离泊，应增加协助拖轮或临时抛锚；
（4）船舶应使用安全航速航行，不能超速。
2．安全保障船舶
   根据通航环境及船舶靠离泊条件，由代理公司向有关单位申请安全保障船舶，该船进出港分别配置拖轮和一艘快速船（"纳川05"）作为航行和靠离泊安全保障船舶（警戒船），如安全保障船因调配临时改变，应由同类型的其他船舶代替执行安全保障任务。
（1）护航拖轮安全保障任务：
①防止船舶出现突发情况时偏出龙腾航道；
②协助船舶（低速时）转向；
③警告穿越航道影响船舶航行安全的其他船舶；
④船舶进出港通过湛江海湾大桥时，负责在大桥区水域实施伴航；
⑤能见度不良时，协助大船在前方1海里范围内进行瞭望。
（2）警戒船（"纳川05"）安全保障任务：
①驱离航道中渔船和其他碍航船舶；
②船舶靠离泊时，在码头附近水域进行警戒，及时警示或驱离闯入码头回旋水域的其他船舶；
③船舶进出港，向船舶通报有关安全航行的相关通航信息。
（3）协助靠离泊拖轮
①确保与船舶联系畅通；
②协助船舶靠离泊和减速、转向等；
③听从引航员指令操作；
④协助船舶紧急情况下救助；
⑤向船舶通报有关安全航行的相关通航信息。
四、引航员安全操作措施及注意事项
（一）靠离泊人员安排
由一名一级或以上责任引航员负责现场指挥引航工作，靠泊时应另加一名全能二级或以上级别引航员作为副班引航员；。
（二）靠泊安全操作措施
1．靠泊时间
根据潮水和船舶吃水，"{chinese_name}"轮定于{A}靠200泊位。
2．人员出海及登轮时间
{format_time_offset(berth_before_5h)}引航员乘拖轮出海，预计于{format_time_offset(berth_before_2h)}抵龙腾登轮点（20°59.5′00″N，110°53′00″E），进港时要求代理提早通知"{chinese_name}"轮按时抵达并按照要求做好准备，保证登轮人员的安全。
3．登轮后准备工作
引航员登轮后，首先安装好导航仪，核查船舶状况是否良好，并在航行中进行转向测试，以便对"{chinese_name}"轮的惯性、转向速度等做到心中有数。确认安全保障船按时到位并建立有效联系。
4．船舶进龙腾航道时间
"{chinese_name}"轮在{format_time_offset(berth_before_1_5h)}左右开始进入龙腾航道，要求两条拖轮于{format_time_offset(berth_before_1_5h)}抵龙11号灯浮附近在距离大船2—4海里范围内护航入港，在{format_time_offset(berth_before_50min)}左右出龙腾航道，"纳川05"轮按时协助护航。
5．协助靠离泊拖轮带拖
船舶预计于{format_time_offset(berth_before_0_5h)}\"{chinese_name}\"轮抵50#浮筒附近，协助靠离泊的拖轮按时抵达并带拖，听从引航员指令协助船舶靠泊，对讲机须置于9频道联系。
6．系缆布置
前后各带8条缆，头尾各4条，横缆前后各2条，倒缆前后各2条，确保船舶靠泊安全。
（三）离泊安全操作措施
1．离泊时间
根据船舶离泊计划，"{chinese_name}"轮定于{E}离200泊位。
2．拖轮带拖及联系方式
协助靠泊的拖轮于{E}抵达泊位并带拖，对讲机须置于9频道联系并确保畅通。
3．登轮时间及准备工作
离港前要求代理提早通知"{chinese_name}"轮按照要求做好准备，保证登离轮人员的安全。{E}引航员登轮，引航员登轮后，首先安装好导航仪，核查并确认船舶各种设备处于良好状态，安全保障船按时到位并建立有效联系。
4．解缆安排
先解头尾缆各4条，接着解前后横缆各2条，最后解前后倒缆各2条，确保离泊安全。
5．船舶进出龙腾航道时间及护航安排
"{chinese_name}"轮在{format_time_offset(departure_after_2h)}左右开始进入龙腾航道，要求两条拖轮于{format_time_offset(departure_after_2h)}抵龙31号灯浮附近在距离大船2—4海里范围内护航出港，"纳川05"轮按时协助护航。预计在{format_time_offset(departure_after_3h)}左右出龙腾航道，{format_time_offset(departure_after_3h20min)}直升机抵龙腾离船地点（21°01′00″N，110°45′00″E）（根据当时吃水确定离船地点）接引航员离船。
五、注意事项
（一）人员上船后要认真核查船舶准备工作，特别要注意吃水和主机情况。
（二）在航行中加强与护航船"纳川05"轮及湛江交管中心的联系，了解其他船舶交通信息。
（三）在航行中注意风流压差，若环境许可，尽量保证大船在航道中心线上，不超速行驶，充分掌握好大船的惯性，合理选择转向时机，防止转向角速度过大，把定不了，冲过头。
（四）船舶靠码头时要控制余速，倒车时尽早控制船首偏转，控制好靠拢速度和靠拢角度，防止碰撞码头。
（五）指泊员在船舶靠离泊半小时前应当到达现场，与引航员保持密切联系，按规定正确显示泊位信号，并及时对港池内码头前沿内小渔船或其他非生产船驱离。
六、 应急措施
（一）引航员或其他相关人员上船后，如果发现风力、能见度、航道等条件达不到规定要求或船舶状况异常（主机故障、舵机失灵、吃水变化等），不能冒险进港，应选择合适水域抛锚待处理正常后才进出港。
（二）进出港时船舶要备妥双锚以便应急抛锚。
（三）如果船舶在航行中发生故障，要立即查明原因，尽可能控制大船能保向航行到安全锚地抛锚。
（四）如果船舶失控，要指挥护航拖轮协助大船减速控向，尽可能控制大船在安全水域，如果损害事故不可避免，尽可能采取各种有效措施（拖轮顶推拖拉、抛制动锚、大船倒车用舵等）使损失减到最少。
（五）应急时如需增加拖轮应向交管中心报告，协调最近的拖轮尽快赶来协助。


（盖章）         （盖章）
{agent}      湛江港引航站
 {current_date}          {current_date}"""

    return application_text, plan_text

def generate_berth_601_text_content(ship_info, Y, A, A_before, E, E_after, B, C, D, F, G, H, I, safety_team_text, current_date):
    """生成601泊位的文本内容 - 完整模板格式"""
    # 基础变量
    chinese_name = ship_info.chinese_name
    english_name = ship_info.english_name
    agent = ship_info.agent
    nationality = ship_info.nationality
    route = ship_info.route
    arrival_time = ship_info.arrival_time
    cargo_type = ship_info.cargo_type
    discharge_amount = ship_info.discharge_amount
    total_cargo = ship_info.total_cargo
    ship_length = ship_info.ship_length
    ship_width = ship_info.ship_width
    gt = ship_info.gt
    nt = ship_info.nt
    dwt = ship_info.dwt
    
    # 时间变量
    berth_time_a = ship_info.berth_time_a
    departure_time_e = ship_info.departure_time_e
    
    # 潮水和吃水变量
    channel_depth = ship_info.channel_depth
    tide_before_b = ship_info.tide_before_b
    tide_berth_c = ship_info.tide_berth_c
    draft_berth_d = ship_info.draft_berth_d
    tide_departure_f = ship_info.tide_departure_f
    tide_after_g = ship_info.tide_after_g
    draft_departure_h = ship_info.draft_departure_h
    keel_height_i = ship_info.keel_height_i
    
    # 计算各种时间偏移
    berth_time = parse_simple_time(berth_time_a)
    departure_time = parse_simple_time(departure_time_e)
    
    berth_before_5_5h = berth_time - timedelta(hours=5.5) if berth_time else None
    berth_before_3h = berth_time - timedelta(hours=3) if berth_time else None
    berth_before_2_5h = berth_time - timedelta(hours=2.5) if berth_time else None
    berth_before_1h = berth_time - timedelta(hours=1) if berth_time else None
    berth_before_0_5h = berth_time - timedelta(minutes=30) if berth_time else None
    
    departure_after_2h = departure_time + timedelta(hours=2) if departure_time else None
    departure_after_3h = departure_time + timedelta(hours=3) if departure_time else None
    departure_after_3h20min = departure_time + timedelta(hours=3, minutes=20) if departure_time else None
    
    # 计算结果
    arrival_safety_depth = Y + B - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    departure_safety_depth = 24.0 + F - H
    berth_berth_safety_depth = 24.0 + C - D
    departure_channel_safety_depth = Y + G - H
    departure_channel_ratio = (departure_channel_safety_depth / H) * 100 if H != 0 else 0
    
    # 海事申请
    application_text = f"""关于"{chinese_name}"轮靠泊作业的申请
湛江海事局：
现有{agent}代理的{nationality}籍（航线：{route}）"{chinese_name}"轮（{english_name}）于{arrival_time}抵港卸{cargo_type}{discharge_amount}吨（全船共{total_cargo}吨）。该轮长度{ship_length}米，宽{ship_width}米，总吨{gt}，净吨{nt}，载重吨{dwt}吨，抵港吃水{D}米。我港可接受该轮抵港卸货，计划{A}靠二分公司601泊位卸货，于{E}离601泊位，离泊吃水{H}米。作业方案如下：
1、{A_before}（硇洲潮高{B}米），龙腾航道浅点水深-{Y}米，{Y}+{B}-{D}={arrival_safety_depth:.2f}米。富裕水深比例：（{Y}+{B}-{D}）÷{D}={arrival_ratio:.2f}%。符合安全要求。{A}靠601泊位，601泊位码头前沿水深为24.00米，码头长度450米，满足靠泊要求。
2、{E}时（潮高{F}米）离400泊位，离泊吃水{H}米，601码头港池水深为24.00米，港池富余水深24.00+{F}-{H}={departure_safety_depth:.2f}米，符合有关船舶靠泊规定的0.5米富余水深的要求。
    3、安全措施：
（1）船舶靠岸速度≤0.06m/s;
  （2）靠泊时最少使用3艘大拖轮助靠泊；  
  （3）为确保船舶安全靠离码头，届时由船方委托代理向清道单位申请安全保障船执行安全保障任务。
这种卸货操作方式我港已进行过多次，积累了不少经验。
此申请妥否？请批示。   

湛江港（集团）股份有限公司
 {current_date}"""

