    berth_before_6h = berth_time - timedelta(hours=6) if berth_time else None
    berth_before_3_5h = berth_time - timedelta(hours=3.5) if berth_time else None
    berth_before_3h = berth_time - timedelta(hours=3) if berth_time else None
    berth_before_2h = berth_time - timedelta(hours=2) if berth_time else None
