def generate_berth_300_text_content(ship_info, Y, A, A_before, E, E_after, B, C, D, F, G, H, I, safety_team_text, current_date):
    """生成300泊位的文本内容 - 完整模板格式"""
    # 基础变量
    chinese_name = ship_info.chinese_name
    english_name = ship_info.english_name
    agent = ship_info.agent
    nationality = ship_info.nationality
