def generate_berth_601_text_content(ship_info, Y, A, A_before, E, E_after, B, C, D, F, G, H, I, safety_team_text, current_date):
    """生成601泊位的文本内容 - 完整模板格式"""
    # 基础变量
    chinese_name = ship_info.chinese_name
    english_name = ship_info.english_name
    agent = ship_info.agent
    nationality = ship_info.nationality
    route = ship_info.route
    arrival_time = ship_info.arrival_time
    cargo_type = ship_info.cargo_type
    discharge_amount = ship_info.discharge_amount
    total_cargo = ship_info.total_cargo
    ship_length = ship_info.ship_length
    ship_width = ship_info.ship_width
    gt = ship_info.gt
    nt = ship_info.nt
    dwt = ship_info.dwt
    
    # 时间变量
    berth_time_a = ship_info.berth_time_a
    departure_time_e = ship_info.departure_time_e
    
    # 潮水和吃水变量
    channel_depth = ship_info.channel_depth
    tide_before_b = ship_info.tide_before_b
    tide_berth_c = ship_info.tide_berth_c
    draft_berth_d = ship_info.draft_berth_d
    tide_departure_f = ship_info.tide_departure_f
    tide_after_g = ship_info.tide_after_g
    draft_departure_h = ship_info.draft_departure_h
    keel_height_i = ship_info.keel_height_i
    
    # 计算各种时间偏移
    berth_time = parse_simple_time(berth_time_a)
    departure_time = parse_simple_time(departure_time_e)
    
    berth_before_5_5h = berth_time - timedelta(hours=5.5) if berth_time else None
    berth_before_3h = berth_time - timedelta(hours=3) if berth_time else None
    berth_before_2_5h = berth_time - timedelta(hours=2.5) if berth_time else None
    berth_before_1h = berth_time - timedelta(hours=1) if berth_time else None
    berth_before_0_5h = berth_time - timedelta(minutes=30) if berth_time else None
    
    departure_after_2h = departure_time + timedelta(hours=2) if departure_time else None
    departure_after_3h = departure_time + timedelta(hours=3) if departure_time else None
    departure_after_3h20min = departure_time + timedelta(hours=3, minutes=20) if departure_time else None
    
    # 计算结果
    arrival_safety_depth = Y + B - D
    arrival_ratio = (arrival_safety_depth / D) * 100 if D != 0 else 0
    departure_safety_depth = 24.0 + F - H
    berth_berth_safety_depth = 24.0 + C - D
    departure_channel_safety_depth = Y + G - H
