    berth_before_2_5h = berth_time - timedelta(hours=2.5) if berth_time else None
    berth_before_1h = berth_time - timedelta(hours=1) if berth_time else None
    berth_before_0_5h = berth_time - timedelta(minutes=30) if berth_time else None
    
    departure_after_2h = departure_time + timedelta(hours=2) if departure_time else None
    departure_after_3h = departure_time + timedelta(hours=3) if departure_time else None
    departure_after_3h20min = departure_time + timedelta(hours=3, minutes=20) if departure_time else None
    
    # 计算结果
    arrival_safety_depth = Y + B - D
