@app.get("/api/records")
async def get_records():
    """获取历史记录"""
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT * FROM records ORDER BY created_at DESC')
    records = [dict(row) for row in cursor.fetchall()]
    conn.close()
    return records

@app.get("/api/records/{record_id}")
async def get_record(record_id: int):
    """获取单个记录"""
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT * FROM records WHERE id = ?', (record_id,))
    record = cursor.fetchone()
    conn.close()
    
    if not record:
        raise HTTPException(status_code=404, detail="记录不存在")
    
    return dict(record)

@app.delete("/api/records/{record_id}")
async def delete_record(record_id: int):
    """删除记录"""
    conn = get_db_connection()
    cursor = conn.cursor()
    
    # 获取记录信息
    cursor.execute('SELECT * FROM records WHERE id = ?', (record_id,))
    record = cursor.fetchone()
    
    if not record:
        conn.close()
        raise HTTPException(status_code=404, detail="记录不存在")
    
    # 删除文件
    if record['application_file'] and os.path.exists(record['application_file']):
        os.remove(record['application_file'])
    if record['plan_file'] and os.path.exists(record['plan_file']):
        os.remove(record['plan_file'])
    
    # 删除数据库记录
    cursor.execute('DELETE FROM records WHERE id = ?', (record_id,))
    conn.commit()
    conn.close()
    
    return {"success": True, "message": "记录删除成功"}

@app.get("/api/download/{file_type}/{record_id}")
async def download_file(file_type: str, record_id: int):
    """下载文件"""
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT * FROM records WHERE id = ?', (record_id,))
    record = cursor.fetchone()
    conn.close()
    
    if not record:
        raise HTTPException(status_code=404, detail="记录不存在")
    
    if file_type == "application":
        file_path = record['application_file']
        filename = f"{record['chinese_name']}_海事局申请.docx"
    elif file_type == "plan":
        file_path = record['plan_file']
        filename = f"{record['chinese_name']}_保障方案.docx"
    else:
        raise HTTPException(status_code=400, detail="无效的文件类型")
    
    if not file_path or not os.path.exists(file_path):
        raise HTTPException(status_code=404, detail="文件不存在")
    
    return FileResponse(
        file_path,
        media_type="application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        filename=filename
    )

